-- Catálogo oficial. Preserva históricos ao desativar registros antigos.
insert into public.products(name,sku,category,unit,min_stock,current_stock,active)
values ('Paieiro 7 Unidades','P7-001','Paieiro','pacote',50,0,true)
on conflict(sku) do update set name=excluded.name,category=excluded.category,unit=excluded.unit,active=true;
update public.products set active=false where sku <> 'P7-001';

