insert into public.clients(name,address,city,state,min_stock,current_stock,active)
select n.name,'Endereço a cadastrar','Poços de Caldas','MG',20,0,true
from melin_client_names n
where not exists (select 1 from public.clients c where lower(trim(c.name))=lower(trim(n.name)));
update public.clients c set active=true where exists (select 1 from melin_client_names n where lower(trim(n.name))=lower(trim(c.name)));
update public.clients c set active=false where not exists (select 1 from melin_client_names n where lower(trim(n.name))=lower(trim(c.name)));
